package ir.tahamohamadi.publication; import ir.tahamohamadi.common.domain.ContentStatus; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import ir.tahamohamadi.media.asset.MediaAsset; import jakarta.persistence.*; import lombok.*; import java.time.*; import java.util.*;
@Entity @Table(name="publication") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class Publication extends AuditedSoftDeletableEntity { @Column(name="publication_key",nullable=false) private String publicationKey; @Enumerated(EnumType.STRING) @Column(name="content_status",nullable=false) private ContentStatus contentStatus; @Enumerated(EnumType.STRING) @Column(name="publication_stage",nullable=false) private PublicationStage publicationStage; private String doi; @Column(name="external_url") private String externalUrl; @Column(name="published_on") private LocalDate publishedOn; private int year; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="cover_media_id") private MediaAsset coverMedia; @Column(name="sort_order") private int sortOrder; private Publication(UUID id,String key,PublicationStage stage,int year,int order,Instant at){initialize(id,at);publicationKey=requireNonBlank(key,"publicationKey");publicationStage=Objects.requireNonNull(stage,"stage");if(year<1000||year>9999)throw new IllegalArgumentException("year must have four digits");if(order<0)throw new IllegalArgumentException("sortOrder must be nonnegative");this.year=year;sortOrder=order;contentStatus=ContentStatus.DRAFT;} public static Publication create(UUID id,String key,PublicationStage stage,int year,int order,Instant at){return new Publication(id,key,stage,year,order,at);} public void publish(){contentStatus=ContentStatus.PUBLISHED;} public void archive(){contentStatus=ContentStatus.ARCHIVED;} }
